      { he: "\u05D5\u05B7\u05EA\u05B9\u05BC\u05D0\u05DB\u05B7\u05DC \u05D1\u05B4\u05BC\u05E7\u05B0\u05E6\u05B5\u05D4 \u05D4\u05B7\u05DE\u05B7\u05BC\u05D7\u05B2\u05E0\u05B6\u05D4 \u2014 \u05D5\u05B7\u05D9\u05B4\u05BC\u05E7\u05B0\u05E8\u05B8\u05D0 \u05E9\u05B5\u05C1\u05DD\u05BE\u05D4\u05B7\u05DE\u05B8\u05BC\u05E7\u05D5\u05B9\u05DD \u05D4\u05B7\u05D4\u05D5\u05BC\u05D0 \u05EA\u05B7\u05BC\u05D1\u05B0\u05E2\u05B5\u05E8\u05B8\u05D4", ref: "\u05D1\u05DE\u05D3\u05D1\u05E8 \u05D9\u05D0, \u05D0\u2013\u05D2", url: "https://www.sefaria.org/Numbers.11.3" }
